member.example:
Bind the AudioSource pitch property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePitchBinder _pitch;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _pitch;
    }


Bind the AudioSource pitch property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourcePitchBinder Pitch =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _pitch;
    }

Switch the AudioSource pitch between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePitchSwitcherBinder _isHighPitch;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighPitch;
    }


Switch the AudioSource pitch between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _highPitch;
        
        [SerializeField] 
        private float _lowPitch;
        
        private AudioSourcePitchSwitcherBinder IsHighPitch => new(
            _audioSource, _highPitch, _lowPitch);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighPitch;
    }
